        val = "alwaysopen" if enabled else "alwaysclose"
        for tag_name in ("azimuth", "zoomlable"):
            elem = root.find(tag_name)
            if elem is not None:
                elem.text = val

        # PUT 更新（移除 ns0: 命名空间前缀）
        xml_str = ET.tostring(root, encoding='unicode')
        xml_str = xml_str.replace('ns0:', '')
